const EgtMoney=(function(){const cents=x=>Math.round(x*100)/100;function zeroBalance(vec){const ids=Object.keys(vec);let sum=0;ids.forEach(id=>{vec[id]=cents(vec[id]);sum+=vec[id]});if(Math.abs(sum)>1e-9&&ids.length){let big=ids[0];ids.forEach(id=>{if(Math.abs(vec[id])>Math.abs(vec[big]))big=id});vec[big]=cents(vec[big]-sum)}return vec}function pairwise(ids,quantityOf,rate){const n=ids.length;const total=ids.reduce((a,id)=>a+quantityOf(id),0);const vec={};ids.forEach(id=>{vec[id]=rate*(n*quantityOf(id)-total)});return zeroBalance(vec)}function teamMatch(teamPlayers,winnerTeam,loserTeam,netPoints,rate){const vec={};const stake=netPoints*rate;const winners=teamPlayers[winnerTeam],losers=teamPlayers[loserTeam];(winners||[]).forEach(pid=>{vec[pid]=stake/winners.length});(losers||[]).forEach(pid=>{vec[pid]=-stake/losers.length});return zeroBalance(vec)}function prizePot(ids,winner,value){const vec={};ids.forEach(id=>{vec[id]=0});if(!winner||!ids.includes(winner))return vec;const others=ids.filter(id=>id!==winner);vec[winner]=value;others.forEach(id=>{vec[id]=-value/others.length});return zeroBalance(vec)}function prizeToWinners(ids,winners,value){const vec={};ids.forEach(id=>{vec[id]=0});const w=(winners||[]).filter(id=>ids.includes(id));const losers=ids.filter(id=>!w.includes(id));if(!w.length||!losers.length||!value)return zeroBalance(vec);const prizeEach=value/w.length;const costEach=value/losers.length;w.forEach(id=>{vec[id]=prizeEach});losers.forEach(id=>{vec[id]=-costEach});return zeroBalance(vec)}function addVec(target,vec,label,breakdown){Object.entries(vec).forEach(([pid,amt])=>{target[pid]=(target[pid]||0)+amt;if(breakdown&&amt)(breakdown[pid]=breakdown[pid]||[]).push({label,amount:cents(amt)})})}function settleMatchPlay(total,matchPlay,val,breakdown){(matchPlay&&matchPlay.matches||[]).forEach(m=>{const stake=m.stakes!=null&&m.stakes!==""?Number(m.stakes):val("nassauPerPoint");const label=m.sides.map(s=>s.map(pid=>pid.slice(0,2)).join("+")).join(" v ");[["front",m.front,1],["back",m.back,1],["overall",m.overall,2]].forEach(([name,seg,units])=>{if(!seg||seg.winner==="halve")return;const winners=seg.winner==="A"?m.sides[0]:m.sides[1];const losers=seg.winner==="A"?m.sides[1]:m.sides[0];const vec={};winners.forEach(pid=>{vec[pid]=units*stake/winners.length});losers.forEach(pid=>{vec[pid]=-(units*stake)/losers.length});addVec(total,zeroBalance(vec),`Match ${label} ${name}`,breakdown)})})}function moneyForRound(model,roundId,results,events,stakes){const md=model.moneyDefaults;const S=stakes&&stakes[roundId]||{};const val=k=>S[k]!=null&&S[k]!==""?Number(S[k]):md[k];const round=model.rounds.find(r=>r.id===roundId);const ids=round.players.slice();const total={};ids.forEach(id=>{total[id]=0});const breakdown={};const teamPlayers={};(round.teams||[]).forEach(t=>{teamPlayers[t.name]=t.players});if(roundId==="R1"){if(results.bbb)addVec(total,prizeToWinners(ids,results.bbb.champions,val("bbbNinesWinner")),"BBB (winner)",breakdown);if(results.nines)addVec(total,prizeToWinners(ids,results.nines.champions,val("bbbNinesWinner")),"Nines (winner)",breakdown)}else if(roundId==="R2"&&results.fourBall){const segs=results.fourBall.segments;[["front",segs.front,model.pointsConfig.R2.nassauFront],["back",segs.back,model.pointsConfig.R2.nassauBack],["overall",segs.overall,model.pointsConfig.R2.nassauOverall]].forEach(([name,m,pts])=>{if(m.winnerTeam==="halve")return;const winner=m.winnerTeam;const loser=round.teams.find(t=>t.name!==winner).name;addVec(total,teamMatch(teamPlayers,winner,loser,pts,val("nassauPerPoint")),`Nassau ${name}`,breakdown)})}else if(roundId==="R3"&&results.wolf){const vec={};ids.forEach(id=>{vec[id]=(results.wolf.units[id]||0)*val("wolfPerUnit")});addVec(total,zeroBalance(vec),"Wolf",breakdown)}else if(roundId==="R4"&&results.teamStableford){const ts=results.teamStableford;const rate=val("nassauPerPoint");const other=name=>(round.teams.find(t=>t.name!==name)||{}).name;const pc=model.pointsConfig.R4||{};ts.segments.forEach((s,i)=>{if(s.winner==="halve")return;addVec(total,teamMatch(teamPlayers,s.winner,other(s.winner),pc.segmentWin||1,rate),`Stableford seg ${i+1}`,breakdown)});if(ts.overallWinner!=="halve"){addVec(total,teamMatch(teamPlayers,ts.overallWinner,other(ts.overallWinner),pc.overall18||2,rate),"Stableford 18 total",breakdown)}}else if(roundId==="R5"){if(results.bbb)addVec(total,pairwise(ids,id=>results.bbb.totals[id]||0,val("bbbNinesPerPointDiff")),"BBB",breakdown)}else if(roundId==="R6"&&results.singles){const rate=val("nassauPerPoint");results.singles.results.forEach(pr=>{[["front",pr.front,1],["back",pr.back,1],["overall",pr.match,2]].forEach(([name,seg,units])=>{if(!seg||seg.winner==="halve")return;const w=seg.winner==="A"?pr.a:pr.b;const l=seg.winner==="A"?pr.b:pr.a;const vec={};vec[w]=units*rate;vec[l]=-units*rate;addVec(total,zeroBalance(vec),`Singles ${pr.a.slice(0,2)}v${pr.b.slice(0,2)} ${name}`,breakdown)})})}settleMatchPlay(total,results.overlayMatchPlay,val,breakdown);if(results.skins&&roundId!=="R1"){addVec(total,pairwise(ids,id=>results.skins.gross.won[id]||0,val("skinsAnte")),"Skins (gross)",breakdown);addVec(total,pairwise(ids,id=>results.skins.net.won[id]||0,val("skinsAnte")),"Skins (net)",breakdown)}((events==null?void 0:events.ctp)||[]).filter(e=>e.round===roundId).forEach(e=>{addVec(total,prizePot(ids,e.player,val("ctpLd")),`CTP h${e.hole}`,breakdown)});((events==null?void 0:events.longDrive)||[]).filter(e=>e.round===roundId).forEach(e=>{addVec(total,prizePot(ids,e.player,val("ctpLd")),`Long Drive h${e.hole}`,breakdown)});zeroBalance(total);return{roundId,total,breakdown,netsToZero:Math.abs(Object.values(total).reduce((a,b)=>a+b,0))<1e-6}}function passTheMoneySettlement(model,ptm){const ids=model.players.map(p=>p.id);const value=(ptm.bill||0)+(ptm.potTotal||0);return{total:prizePot(ids,ptm.finalHolder,value),value,holder:ptm.finalHolder}}function compute(model,resultsByRound,events,ptm,stakes){const ids=model.players.map(p=>p.id);const total={};ids.forEach(id=>{total[id]=0});const rounds={};model.rounds.forEach(round=>{if(!resultsByRound[round.id])return;const rm=moneyForRound(model,round.id,resultsByRound[round.id],events,stakes);rounds[round.id]=rm;Object.entries(rm.total).forEach(([pid,amt])=>{total[pid]=(total[pid]||0)+amt})});if(ptm&&ptm.finalHolder){const s=passTheMoneySettlement(model,ptm);rounds.passTheMoney=s;Object.entries(s.total).forEach(([pid,amt])=>{total[pid]=(total[pid]||0)+amt})}zeroBalance(total);return{rounds,total,netsToZero:Math.abs(Object.values(total).reduce((a,b)=>a+b,0))<1e-6}}return{cents,zeroBalance,pairwise,teamMatch,prizePot,prizeToWinners,moneyForRound,passTheMoneySettlement,compute}})();if(typeof window!=="undefined"){Object.assign(window,{EgtMoney})}
